INSERT INTO os_metric_agg_1m ( instance_id, collected_at, avg_cpu_usage, avg_memory_usage, avg_disk_used_bytes, avg_disk_total_bytes, avg_net_rx_bytes, avg_net_tx_bytes, record_count, created_at ) SELECT instance_id, collected_at, MAX(CASE WHEN metric_type = 'CPU' THEN avg_value END) as avg_cpu_usage, MAX(CASE WHEN metric_type = 'MEMORY' THEN avg_value END) as avg_memory_usage, MAX(CASE WHEN metric_type = 'DISK_USAGE' THEN avg_value END) as avg_disk_used_bytes, MAX(CASE WHEN metric_type = 'DISK_USAGE' THEN max_value END) as avg_disk_total_bytes, MAX(CASE WHEN metric_type = 'DISK_READ' THEN avg_value END) as avg_net_rx_bytes, MAX(CASE WHEN metric_type = 'DISK_WRITE' THEN avg_value END) as avg_net_tx_bytes, MAX(sample_count) as record_count, NOW() FROM ( VALUES
(#{item.instanceId}, #{item.collectedAt}, #{item.metricType}, #{item.avgValue}, #{item.maxValue}, #{item.sampleCount})
) AS t(instance_id, collected_at, metric_type, avg_value, max_value, sample_count) GROUP BY instance_id, collected_at
